mapper.select:
SELECT r.parking_roi_id, r.slot_id, r.image_width, r.image_height, r.roi_polygon, r.del_flag, r.create_by, r.create_time, r.update_by, r.update_time, r.remark, COALESCE(s.slot_code, r.slot_code) AS slot_code, s.camera_id, COALESCE(c.camera_name, r.camera_name) AS camera_name FROM biz_parking_roi r LEFT JOIN biz_parking_slot s ON r.slot_id = s.parking_slot_id AND s.del_flag = '0' LEFT JOIN dev_camera c ON s.camera_id = c.camera_id AND c.del_flag = '0' WHERE r.del_flag = '0'
AND r.slot_id = #{roi.slotId}
AND COALESCE(s.slot_code, r.slot_code) LIKE CONCAT('%', #{roi.slotCode}, '%')
AND COALESCE(c.camera_name, r.camera_name) LIKE CONCAT('%', #{roi.cameraName}, '%')
AND r.image_width = #{roi.imageWidth}
AND r.image_height = #{roi.imageHeight}
AND r.create_time >= CONCAT(#{roi.params['begincreate_time']}, ' 00:00:00')
AND r.create_time <= CONCAT(#{roi.params['endcreate_time']}, ' 23:59:59')
ORDER BY r.parking_roi_id ASC
